const AWS = require('aws-sdk');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    try {
        const bucket = event.Records[0].s3.bucket.name;
        const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
        
        // Read the file from S3
        const params = {
            Bucket: bucket,
            Key: key
        };
        const data = await s3.getObject(params).promise();
        
        // Process the file (dummy processing for example)
        const processedData = processFile(data.Body);
        
        // Save the processed file to another S3 location
        const outputBucket = 'processed-files-bucket'; // Change to your output bucket
        const outputKey = `processed/${key}`;
        const putParams = {
            Bucket: outputBucket,
            Key: outputKey,
            Body: processedData,
            ContentType: 'application/octet-stream'
        };
        await s3.putObject(putParams).promise();
        
        return { status: 'File processed successfully' };
    } catch (error) {
        console.error('Error processing file:', error);
        throw new Error('Error processing file');
    }
};

